var controller = UnityEngine.Object.FindObjectOfType<LightningSkillController>();
var rangeIndicator = UnityEngine.GameObject.Find("RangeIndicator");
if (controller != null && rangeIndicator != null)
{
    var field = controller.GetType().GetField("_rangeIndicator", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
    field.SetValue(controller, rangeIndicator);
    UnityEngine.Debug.Log($"Assigned RangeIndicator to LightningSkillController. Active: {rangeIndicator.activeSelf}");
}
else
{
    if (controller == null) UnityEngine.Debug.LogError("LightningSkillController not found");
    if (rangeIndicator == null) UnityEngine.Debug.LogError("RangeIndicator not found");
}

