args.script:
// 1. Create LightningSkillController object
var controllerObj = new UnityEngine.GameObject("LightningSkillController");
controllerObj.AddComponent<LightningSkillController>();
controllerObj.AddComponent<UnityEngine.AudioSource>();

// 2. Create RangeIndicator (inactive, with LineRenderer circle)
var rangeObj = new UnityEngine.GameObject("RangeIndicator");
rangeObj.SetActive(false);
var rangeLR = rangeObj.AddComponent<UnityEngine.LineRenderer>();
var mat = new UnityEngine.Material(UnityEngine.Shader.Find("Unlit/Transparent"));
if (mat != null) { mat.color = new UnityEngine.Color(0.3f, 0.6f, 1f, 0.6f); rangeLR.material = mat; }
rangeLR.useWorldSpace = true;
rangeLR.startWidth = 0.15f; rangeLR.endWidth = 0.15f;
rangeLR.loop = true;
int segments = 64; float radius = 5f;
rangeLR.positionCount = segments + 1;
for (int i = 0; i <= segments; i++)
{
    float angle = (float)i / segments * UnityEngine.Mathf.PI * 2f;
    rangeLR.SetPosition(i, new UnityEngine.Vector3(UnityEngine.Mathf.Cos(angle) * radius, 0.05f, UnityEngine.Mathf.Sin(angle) * radius));
}
rangeObj.transform.position = UnityEngine.Vector3.zero;

// 3. Create Skill Button UI
var canvas = UnityEngine.Object.FindObjectOfType<UnityEngine.Canvas>();
var buttonObj = new UnityEngine.GameObject("SkillButton_Lightning");
buttonObj.transform.SetParent(canvas.transform, false);
var buttonRect = buttonObj.AddComponent<UnityEngine.RectTransform>();
buttonRect.anchorMin = new UnityEngine.Vector2(0.5f, 0f);
buttonRect.anchorMax = new UnityEngine.Vector2(0.5f, 0f);
buttonRect.sizeDelta = new UnityEngine.Vector2(70f, 70f);
buttonRect.anchoredPosition = new UnityEngine.Vector2(0f, 60f);
buttonRect.pivot = new UnityEngine.Vector2(0.5f, 0.5f);

var buttonImage = buttonObj.AddComponent<UnityEngine.UI.Image>();
buttonImage.color = new UnityEngine.Color(0.2f, 0.3f, 0.6f, 0.9f);
buttonObj.AddComponent<UnityEngine.UI.Button>();
var outline = buttonObj.AddComponent<UnityEngine.UI.Outline>();
outline.effectColor = new UnityEngine.Color(0.3f, 0.6f, 1f, 1f);
outline.effectDistance = new UnityEngine.Vector2(2f, -2f);

// Icon child
var iconObj = new UnityEngine.GameObject("Icon");
iconObj.transform.SetParent(buttonObj.transform, false);
var iconRect = iconObj.AddComponent<UnityEngine.RectTransform>();
iconRect.anchorMin = UnityEngine.Vector2.zero;
iconRect.anchorMax = UnityEngine.Vector2.one;
iconRect.sizeDelta = UnityEngine.Vector2.zero;
iconRect.pivot = new UnityEngine.Vector2(0.5f, 0.5f);

var iconImage = iconObj.AddComponent<UnityEngine.UI.Image>();
iconImage.color = UnityEngine.Color.cyan;
iconImage.raycastTarget = false;
iconImage.preserveAspect = true;

// Load lightning sprite
var spritePath = "Assets/TJGenerators/History/Sprite_20260601_102826.png";
var loadedSprites = UnityEditor.AssetDatabase.LoadAllAssetsAtPath(spritePath);
foreach (var asset in loadedSprites)
{
    if (asset is UnityEngine.Sprite s) { iconImage.sprite = s; iconImage.color = UnityEngine.Color.white; break; }
}

// 4. Wire references via reflection
var ctrl = controllerObj.GetComponent<LightningSkillController>();
var bf = System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance;
ctrl.GetType().GetField("_rangeIndicator", bf).SetValue(ctrl, rangeObj);
ctrl.GetType().GetField("_skillButton", bf).SetValue(ctrl, buttonObj.GetComponent<UnityEngine.UI.Button>());
ctrl.GetType().GetField("_mainCamera", bf).SetValue(ctrl, UnityEngine.Camera.main);
ctrl.GetType().GetField("_audioSource", bf).SetValue(ctrl, controllerObj.GetComponent<UnityEngine.AudioSource>());

// _lightningBoltPrefab is GameObject type
var boltPrefab = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.GameObject>("Assets/Prefabs/Skills/LightningBolt.prefab");
if (boltPrefab != null) ctrl.GetType().GetField("_lightningBoltPrefab", bf).SetValue(ctrl, boltPrefab);

// _lightningImpactPrefab is ParticleSystem type - get the component from the prefab
var impactGO = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.GameObject>("Assets/Prefabs/Skills/LightningImpact.prefab");
if (impactGO != null)
{
    var ps = impactGO.GetComponent<UnityEngine.ParticleSystem>();
    if (ps != null) ctrl.GetType().GetField("_lightningImpactPrefab", bf).SetValue(ctrl, ps);
    else UnityEngine.Debug.LogWarning("No ParticleSystem on LightningImpact prefab");
}

UnityEngine.Debug.Log("Lightning skill objects created and wired in GameScene!");

