        for (int i = 0; i < _boltCount - 1; i++)
        {
            Vector3 offset = Random.insideUnitCircle * _skillRange * 0.7f;
            Vector3 boltTarget = _targetPos + new Vector3(offset.x, 0, offset.y);
            Vector3 boltOrigin = boltTarget + Vector3.up * (_boltHeight + Random.Range(-3f, 3f));

