args.script:
// Rebuild RangeIndicator as 2D circle on XY plane
var rangeObj = UnityEngine.GameObject.Find("RangeIndicator");
if (rangeObj == null)
{
    foreach (var t in UnityEngine.Resources.FindObjectsOfTypeAll<UnityEngine.Transform>())
    {
        if (t.name == "RangeIndicator") { rangeObj = t.gameObject; break; }
    }
}
if (rangeObj != null)
{
    var lr = rangeObj.GetComponent<UnityEngine.LineRenderer>();
    if (lr != null)
    {
        lr.useWorldSpace = true;
        lr.loop = true;
        lr.sortingOrder = 1;

        int segments = 64;
        float radius = 5f;
        lr.positionCount = segments + 1;
        for (int i = 0; i <= segments; i++)
        {
            float angle = (float)i / segments * UnityEngine.Mathf.PI * 2f;
            float x = UnityEngine.Mathf.Cos(angle) * radius;
            float y = UnityEngine.Mathf.Sin(angle) * radius;
            lr.SetPosition(i, new UnityEngine.Vector3(x, y, 0f));
        }
        UnityEngine.Debug.Log("RangeIndicator rebuilt as 2D circle on XY plane");
    }
}

